1	export const runScenario = (_scenario: unknown): unknown => {
2	  return { results: [{ premium: 5 }] };
3	};
4

1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Edge case: empty
6	  it("empty item list → premium 5 G (only the processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // Base premiums per item type (with fee)
15	  it.todo("single sword (plain, low enchantment) → 100 G base + 10 G first insurance + 5 G fee = 115 G");
16	  it.todo("single amulet (plain, low enchantment) → 60 G base + 6 G first insurance + 5 G fee = 71 G");
17	  it.todo("single staff (plain, low enchantment) → 80 G base + 8 G first insurance + 5 G fee = 93 G");
18	  it.todo("single potion (plain, low enchantment) → 40 G base + 4 G first insurance + 5 G fee = 49 G");
19	
20	  // Component pricing and building blocks
21	  it.todo("2 runes → 50 G base premium (plus first-insurance and fee)");
22	  it.todo("3 runes → 60 G base premium (block applies)");
23	  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
24	  it.todo("7 runes → 175 G base premium (one block of 3 at 60 G + 4 singles at 25 G)");
25	
26	  // Alike components clarification
27	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
28	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
29	
30	  // Individual modifiers
31	  it.todo("cursed sword adds 50% surcharge to that item's base premium");
32	  it.todo("highly enchanted item (enchantment ≥ 5) adds 30% surcharge to that item");
33	  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
34	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
35	  it.todo("sword with enchantment 5 and cursed → both surcharges apply");
36	  it.todo("long-standing customer (≥ 2 years) → 20% loyalty discount on policy base");
37	  it.todo("customer with exactly 2 years → loyalty discount applies");
38	  it.todo("first insurance → 10% initial assessment surcharge per item");
39	  it.todo("follow-up contract (second quote+) → 15% discount on policy base");
40	
41	  // Modifier scope on multi-item policies
42	  it.todo("cursed sword + plain amulet → policy base 160 G + 50 G curse (item-scoped) → 210 G before fee");
43	
44	  // Rounding
45	  it.todo("premium that yields 197.5 G rounds up to 198 G (MHPCO's favor)");
46	  it.todo("payout that yields 350.5 G rounds down to 350 G (MHPCO's favor)");
47	
48	  // Integration examples
49	  it.todo("newcomer with cursed sword (steel, enchantment 3) → 165 G");
50	  it.todo("long-standing customer's second contract with cursed sword (enchantment 7) → 160 G");
51	
52	  // Claims — standard reimbursement
53	  it.todo("regular sword (steel, enchantment 3) damage 500 G → payout 400 G");
54	  it.todo("rune damage 200 G → payout 100 G (no special clause)");
55	
56	  // Claim — high enchantment
57	  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");
58	
59	  // Claim — dragon material
60	  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (full minus deductible)");
61	
62	  // Claim — both clauses: 50% rule wins
63	  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");
64	  it.todo("dragon-material sword, enchantment 8, damage 1000 G → payout 400 G (high-enchantment wins at threshold)");
65	
66	  // Multiple damages: deductible per event
67	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible once per item)");
68	
69	  // Cap rules
70	  it.todo("sword + amulet policy → insurance sum 1600 G, cap 3200 G");
71	  it.todo("cursed sword → cap 2000 G (based on unmodified insurance value, not modified premium)");
72	  it.todo("sword + 3-rune block → insurance sum 1750 G (block discount affects premium only)");
73	
74	  // Cap exhaustion across claims
75	  it.todo("sword (cap 2000); first claim 1500 → payout 1400, remainingCap 600");
76	  it.todo("sword (cap 2000); after first 1500 claim, second 1500 → payout 600, remainingCap 0");
77	
78	  // Multiple items of same type
79	  it.todo("policy with two swords → insurance sum 2000 G, cap 4000 G");
80	  it.todo("dragon attack damages both swords (two entries) → each gets its own deductible");
81	  it.todo("more sword damages than insured swords → CLI exits non-zero, claim rejected");
82	
83	  // Edge cases / errors
84	  it.todo("quote with unknown item type → CLI exits non-zero, error to stderr, no results");
85	  it.todo("claim references item not in policy → CLI exits non-zero, error to stderr");
86	  it.todo("claim with negative damage amount → CLI exits non-zero, error to stderr");
87	
88	  // Sanity check that runScenario exists for tests to import
89	  it("module exports runScenario", () => {
90	    expect(typeof runScenario).toBe("function");
91	  });
92	});
